311→interface CommentThreadProps {
312→  comment: AnnotationComment
313→  replies: AnnotationComment[]
314→  currentUserId: number
315→  onReplyClick: (commentId: number) => void
316→  activeReplyId: number | null
317→  onUpdate: (comment: AnnotationComment) => void
318→  onDelete: (commentId: number) => void
319→}
320→
321→function CommentThread({
322→  comment,
323→  replies,
324→  currentUserId,
325→  onReplyClick,
326→  activeReplyId,
327→  onUpdate,
328→  onDelete,
329→}: Readonly<CommentThreadProps>) {
330→  const [editing, setEditing] = useState(false)
331→  const [editText, setEditText] = useState(comment.content)
332→  const [saving, setSaving] = useState(false)
333→
334→  const handleSaveEdit = async () => {
335→    if (!editText.trim() || saving) return
336→    setSaving(true)
337→    try {
338→      const updated = await api.updateAnnotationComment(comment.id, { content: editText.trim() })
339→      onUpdate(updated)
340→      setEditing(false)
341→    } catch {
342→      // silent fail
343→    } finally {
344→      setSaving(false)
345→    }
346→  }
347→
348→  const handleDelete = async () => {
349→    if (!confirm('Delete this comment?')) return
350→    try {
351→      await api.deleteAnnotationComment(comment.id)
352→      onDelete(comment.id)
353→    } catch {
354→      // silent fail
355→    }
356→  }
357→
358→  return (
359→    <div className={`${comment.resolved ? 'opacity-50' : ''}`}>
360→      <div className="flex items-start gap-2 text-xs">
361→        <div className="w-5 h-5 rounded-full bg-dark-bg-tertiary flex items-center justify-center text-dark-text-tertiary flex-shrink-0 mt-0.5 text-[10px] font-bold">
362→          {(comment.author_name ?? '?')[0].toUpperCase()}
363→        </div>
364→        <div className="flex-1 min-w-0">
365→          <div className="flex items-center gap-1.5 mb-0.5">
366→            <Link
367→              to={`/app/users/${comment.author_id}`}
368→              className="font-medium text-dark-text-primary hover:text-primary-400 transition-colors"
369→            >
370→              {comment.author_name ?? 'Unknown'}
371→            </Link>
372→            <span className="text-dark-text-tertiary">{new Date(comment.created_at).toLocaleString(undefined, { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}</span>
373→            {comment.resolved && <span className="text-green-400 text-[10px]">resolved</span>}
374→          </div>
375→          {editing ? (
376→            <div className="flex gap-1.5 mt-1">
377→              <textarea
378→                value={editText}
379→                onChange={(e) => setEditText(e.target.value)}
380→                rows={2}
381→                autoFocus
382→                className="flex-1 px-2 py-1 bg-dark-bg-primary border border-primary-500 rounded text-xs text-dark-text-primary focus:outline-none resize-none"
383→              />
384→              <div className="flex flex-col gap-1">
385→                <button
386→                  onClick={handleSaveEdit}
387→                  disabled={saving}
388→                  className="px-2 py-1 bg-primary-600 text-white rounded text-[10px] hover:bg-primary-500 disabled:opacity-40"
389→                >
390→                  Save
391→                </button>
392→                <button
393→                  onClick={() => { setEditing(false); setEditText(comment.content) }}
394→                  className="px-2 py-1 bg-dark-bg-tertiary text-dark-text-secondary rounded text-[10px] hover:bg-dark-bg-tertiary/80"
395→                >
396→                  Cancel
397→                </button>
398→              </div>
399→            </div>
400→          ) : (
401→            <p className="text-dark-text-secondary whitespace-pre-wrap break-words">{comment.content}</p>
402→          )}
403→          <div className="flex items-center gap-2 mt-1">
404→            <button
405→              onClick={() => onReplyClick(comment.id)}
406→              className={`text-[10px] transition-colors ${activeReplyId === comment.id ? 'text-primary-400' : 'text-dark-text-tertiary hover:text-dark-text-secondary'}`}
407→            >
408→              Reply
409→            </button>
410→            {currentUserId === comment.author_id && !editing && (
411→              <>
412→                <button
413→                  onClick={() => setEditing(true)}
414→                  className="text-[10px] text-dark-text-tertiary hover:text-dark-text-secondary transition-colors"
415→                >
416→                  Edit
417→                </button>
418→                <button
419→                  onClick={handleDelete}
420→                  className="text-[10px] text-dark-text-tertiary hover:text-red-400 transition-colors"
421→                >
422→                  Delete
423→                </button>
424→              </>
425→            )}
426→          </div>
427→        </div>
428→      </div>
429→
430→      {/* Nested replies */}
431→      {replies.length > 0 && (
432→        <div className="ml-7 mt-1.5 space-y-1.5 border-l border-dark-border-subtle/50 pl-2">
433→          {replies.map(reply => (
434→            <CommentThread
435→              key={reply.id}
436→              comment={reply}
437→              replies={[]} // only one level of nesting for MVP
438→              currentUserId={currentUserId}
439→              onReplyClick={onReplyClick}
440→              activeReplyId={activeReplyId}
441→              onUpdate={onUpdate}
442→              onDelete={onDelete}
443→            />
444→          ))}
445→        </div>
446→      )}
447→    </div>
448→  )
449→}
