352→// ── Comment handlers ───────────────────────────────────────────────────────
353→
354→// HandleCreateAnnotationComment adds a comment or reply to an annotation.
355→func (s *Server) HandleCreateAnnotationComment(w http.ResponseWriter, r *http.Request) {
356→	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
357→	defer cancel()
358→
359→	userID := r.Context().Value(UserIDKey).(int64)
360→	annotationID, err := strconv.ParseInt(chi.URLParam(r, "annotationId"), 10, 64)
361→	if err != nil {
362→		respondError(w, http.StatusBadRequest, "invalid annotation ID", "invalid_input")
363→		return
364→	}
365→
366→	var req struct {
367→		Content         string `json:"content"`
368→		ParentCommentID *int64 `json:"parent_comment_id,omitempty"`
369→	}
370→	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
371→		respondError(w, http.StatusBadRequest, errInvalidRequestBody, "invalid_input")
372→		return
373→	}
374→	if req.Content == "" {
375→		respondError(w, http.StatusBadRequest, "content is required", "invalid_input")
376→		return
377→	}
378→	if len(req.Content) > 5000 {
379→		respondError(w, http.StatusBadRequest, "content too long (max 5000 characters)", "invalid_input")
380→		return
381→	}
382→
383→	// Verify annotation exists and user has access
384→	var pageID int64
385→	if err := s.db.QueryRowContext(ctx,
386→		`SELECT wiki_page_id FROM wiki_annotations WHERE id = $1`, annotationID,
387→	).Scan(&pageID); err != nil {
388→		respondError(w, http.StatusNotFound, "annotation not found", "not_found")
389→		return
390→	}
391→
392→	if err := s.checkWikiPageAccess(ctx, userID, pageID); err != nil {
393→		handleWikiAccessError(w, err)
394→		return
395→	}
396→
397→	// Fetch project_id for notifications
398→	var projectID int64
399→	_ = s.db.QueryRowContext(ctx, `SELECT project_id FROM wiki_pages WHERE id = $1`, pageID).Scan(&projectID)
400→
401→	var commentID int64
402→	err = s.db.QueryRowContext(ctx, `
403→		INSERT INTO wiki_annotation_comments (annotation_id, author_id, parent_comment_id, content)
404→		VALUES ($1, $2, $3, $4)
405→		RETURNING id
406→	`, annotationID, userID, req.ParentCommentID, req.Content).Scan(&commentID)
407→	if err != nil {
408→		s.logger.Error("Failed to create annotation comment", zap.Error(err))
409→		respondError(w, http.StatusInternalServerError, "failed to create comment", "internal_error")
410→		return
411→	}
412→
413→	comment := s.fetchAnnotationCommentByID(ctx, commentID)
414→	if comment == nil {
415→		respondError(w, http.StatusInternalServerError, "failed to fetch created comment", "internal_error")
416→		return
417→	}
418→
419→	// Notifications (best-effort, non-blocking)
420→	if projectID > 0 {
421→		commenterName := ""
422→		if comment.AuthorName != nil {
423→			commenterName = *comment.AuthorName
424→		}
425→		annLink := "/app/projects/" + int64ToStr(projectID) + "/wiki?page=" + int64ToStr(pageID) + "&annotation=" + int64ToStr(annotationID)
426→		go s.notifyAnnotationComment(context.Background(), annotationID, projectID, userID, commentID, req.Content, commenterName, annLink, req.ParentCommentID)
427→	}
428→
429→	respondJSON(w, http.StatusCreated, comment)
430→}
