432→// HandleUpdateAnnotationComment edits or resolves a comment (author only).
433→func (s *Server) HandleUpdateAnnotationComment(w http.ResponseWriter, r *http.Request) {
434→	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
435→	defer cancel()
436→
437→	userID := r.Context().Value(UserIDKey).(int64)
438→	commentID, err := strconv.ParseInt(chi.URLParam(r, "commentId"), 10, 64)
439→	if err != nil {
440→		respondError(w, http.StatusBadRequest, "invalid comment ID", "invalid_input")
441→		return
442→	}
443→
444→	var req struct {
445→		Content  *string `json:"content,omitempty"`
446→		Resolved *bool   `json:"resolved,omitempty"`
447→	}
448→	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
449→		respondError(w, http.StatusBadRequest, errInvalidRequestBody, "invalid_input")
450→		return
451→	}
452→
453→	var authorID int64
454→	var annotationID int64
455→	if err := s.db.QueryRowContext(ctx,
456→		`SELECT author_id, annotation_id FROM wiki_annotation_comments WHERE id = $1`, commentID,
457→	).Scan(&authorID, &annotationID); err != nil {
458→		respondError(w, http.StatusNotFound, "comment not found", "not_found")
459→		return
460→	}
461→
462→	if authorID != userID {
463→		respondError(w, http.StatusForbidden, "only the author can edit this comment", "forbidden")
464→		return
465→	}
466→
467→	if req.Content != nil {
468→		if len(*req.Content) > 5000 {
469→			respondError(w, http.StatusBadRequest, "content too long (max 5000 characters)", "invalid_input")
470→			return
471→		}
472→		if _, err := s.db.ExecContext(ctx,
473→			`UPDATE wiki_annotation_comments SET content = $1, updated_at = NOW() WHERE id = $2`,
474→			*req.Content, commentID,
475→		); err != nil {
476→			s.logger.Error("Failed to update annotation comment content", zap.Error(err))
477→			respondError(w, http.StatusInternalServerError, "failed to update comment", "internal_error")
478→			return
479→		}
480→	}
481→
482→	if req.Resolved != nil {
483→		if _, err := s.db.ExecContext(ctx,
484→			`UPDATE wiki_annotation_comments SET resolved = $1, updated_at = NOW() WHERE id = $2`,
485→			*req.Resolved, commentID,
486→		); err != nil {
487→			s.logger.Error("Failed to update annotation comment resolved", zap.Error(err))
488→			respondError(w, http.StatusInternalServerError, "failed to update comment", "internal_error")
489→			return
490→		}
491→	}
492→
