539→func (s *Server) fetchAnnotationByID(ctx context.Context, annotationID int64) *WikiAnnotation {
540→	var a WikiAnnotation
541→	err := s.db.QueryRowContext(ctx, `
542→		SELECT a.id, a.wiki_page_id, a.author_id, u.name,
543→		       a.start_offset, a.end_offset, a.selected_text, a.color, a.resolved, a.created_at
544→		FROM wiki_annotations a
545→		LEFT JOIN users u ON u.id = a.author_id
546→		WHERE a.id = $1
547→	`, annotationID).Scan(
548→		&a.ID, &a.WikiPageID, &a.AuthorID, &a.AuthorName,
549→		&a.StartOffset, &a.EndOffset, &a.SelectedText, &a.Color, &a.Resolved, &a.CreatedAt,
550→	)
551→	if err != nil {
552→		return nil
553→	}
