556→	rows, err := s.db.QueryContext(ctx, `
557→		SELECT c.id, c.annotation_id, c.author_id, u.name, c.parent_comment_id,
558→		       c.content, c.resolved, c.created_at, c.updated_at
559→		FROM wiki_annotation_comments c
560→		LEFT JOIN users u ON u.id = c.author_id
561→		WHERE c.annotation_id = $1
562→		ORDER BY c.created_at ASC
563→	`, annotationID)
564→	if err != nil {
565→		return &a
566→	}
567→	defer rows.Close()
568→	for rows.Next() {
