571→			&c.ID, &c.AnnotationID, &c.AuthorID, &c.AuthorName,
572→			&c.ParentCommentID, &c.Content, &c.Resolved, &c.CreatedAt, &c.UpdatedAt,
573→		); scanErr == nil {
574→			a.Comments = append(a.Comments, c)
575→		}
576→	}
577→	return &a
578→}
