{!isFullscreen && (
  <div className="flex flex-col h-full">
    {/* Header */}
    <div className="border-b border-dark-border-subtle bg-dark-bg-secondary px-6 py-4">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-dark-text-primary">{page.title}</h1>
          <div className="flex items-center gap-2 mt-1 text-xs text-dark-text-tertiary">
            {page.creator_name && (
              <span>Created by{' '}
                <Link to={`/app/users/${page.created_by}`} className="text-dark-text-secondary hover:text-primary-400 transition-colors">
                  {page.creator_name}
                </Link>
                {' '}· {new Date(page.created_at).toLocaleDateString()}
              </span>
            )}
            {(lastEditedBy || lastEditedAt) && (
              <>
                <span className="text-dark-border-subtle">·</span>
                <span>
                  Last edited{lastEditedBy ? <> by{' '}
                    <Link to={`/app/users/${page.updated_by ?? page.created_by}`} className="text-dark-text-secondary hover:text-primary-400 transition-colors">
                      {lastEditedBy}
                    </Link>
                  </> : ''}{' '}
                  · {new Date(lastEditedAt).toLocaleString()}
                </span>
              </>
            )}
          </div>
          <div className="flex items-center gap-3 mt-2">
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${getSaveStatusColor(saveStatus, syncState)}`} />
              <span className="text-sm text-dark-text-tertiary">
                {getSaveStatusText(saveStatus, autoSaveEnabled)}
              </span>
            </div>
            <button
              onClick={() => setAutoSaveEnabled(prev => !prev)}
              className={`px-2 py-0.5 rounded text-xs font-medium transition-colors ${
                autoSaveEnabled
                  ? 'bg-green-500/15 text-green-400 hover:bg-green-500/25'
                  : 'bg-dark-bg-tertiary text-dark-text-tertiary hover:bg-dark-bg-tertiary/80'
              }`}
              title={autoSaveEnabled ? 'Disable autosave' : 'Enable autosave'}
            >
              {autoSaveEnabled ? 'Auto' : 'Manual'}
            </button>
            <button
              onClick={() => saveNow(true)}

