// ── Component ────────────────────────────────────────────────────

export default function WikiEditor({ page, annotations, selectedAnnotationId, showAnnotationHighlights = true, onAnnotationCreate, onAnnotationClick, onAnnotationUpdate, onAnnotationDelete, onCommentCreate, onCommentUpdate, onCommentDelete, showResolved = false, onToggleShowResolved }: Readonly<WikiEditorProps>) {
  const navigate = useNavigate()
  const { user } = useAuth()
  const [content, setContent] = useState('')
  const [isPreview, setIsPreview] = useState(true)
  const [previewHTML, setPreviewHTML] = useState('')
  const [syncState, setSyncState] = useState<SyncState>('connecting')
  const [showImagePicker, setShowImagePicker] = useState(false)
  const [showFigmaInput, setShowFigmaInput] = useState(false)
  const [figmaInputUrl, setFigmaInputUrl] = useState('')
  const [figmaInputError, setFigmaInputError] = useState('')
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('idle')
  const [autoSaveEnabled, setAutoSaveEnabled] = useState(true)
  const isDirtyRef = useRef(false)
  const contentRef = useRef('')
  const lastSavedContentRef = useRef('')
  const isSavingRef = useRef(false)
  const [isFullscreen, setIsFullscreen] = useState(false)
  const [fsPreviewHTML, setFsPreviewHTML] = useState('')
  const [fsAnnotationsVisible, setFsAnnotationsVisible] = useState(false)

  const ydocRef = useRef<Y.Doc | null>(null)
  const providerRef = useRef<WebsocketProvider | null>(null)
  const textareaRef = useRef<HTMLTextAreaElement>(null)
  const fsTextareaRef = useRef<HTMLTextAreaElement>(null)
  const previewTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const abortRef = useRef<AbortController | null>(null)
  const dividerRef = useRef<HTMLButtonElement>(null)
  const fsContainerRef = useRef<HTMLDivElement>(null)
  const previewRef = useRef<HTMLDivElement>(null)
  const fsPreviewRef = useRef<HTMLDivElement>(null)
  const [fsSplitPct, setFsSplitPct] = useState(50)

  // ── Page metadata (creator / last editor) ────────────────────
  const [lastEditedBy, setLastEditedBy] = useState<string | null>(
    page.updater_name ?? page.creator_name ?? null,
  )
  const [lastEditedAt, setLastEditedAt] = useState<string>(page.updated_at)

  // ── Version history state ─────────────────────────────────────
  const [showVersionHistory, setShowVersionHistory] = useState(false)
  const [versions, setVersions] = useState<WikiPageVersion[]>([])
  const [versionsLoading, setVersionsLoading] = useState(false)
  const [viewingVersion, setViewingVersion] = useState<WikiPageVersionWithContent | null>(null)

  // ── Annotation: delegate to window.GoWikiAnnotations (go-wiki package) ──
  // Attach/detach the color picker and click handler whenever preview is active.
  useEffect(() => {
    const el = previewRef.current
    if (!el || !isPreview || !window.GoWikiAnnotations) return
    const detach = window.GoWikiAnnotations.attach(el, {
      onAnnotationCreate: onAnnotationCreate
        ? (data) => onAnnotationCreate({ startOffset: data.startOffset, endOffset: data.endOffset, selectedText: data.selectedText, color: data.color as AnnotationColor })
        : undefined,
      onAnnotationClick,
    })
    return detach
  }, [isPreview, onAnnotationCreate, onAnnotationClick, previewHTML])

  // Apply highlights after previewHTML renders or annotations change
  useEffect(() => {
    const el = previewRef.current
    if (!el || !window.GoWikiAnnotations) return
    window.GoWikiAnnotations.apply(el, showAnnotationHighlights ? (annotations ?? []) : [], selectedAnnotationId)
  }, [previewHTML, annotations, selectedAnnotationId, showAnnotationHighlights])

  // ── Fullscreen annotation support ────────────────────────────
  // Attach color picker to the fullscreen preview pane
  useEffect(() => {
    const el = fsPreviewRef.current
    if (!el || !isFullscreen || !window.GoWikiAnnotations) return
    const detach = window.GoWikiAnnotations.attach(el, {
      onAnnotationCreate: onAnnotationCreate
        ? (data) => onAnnotationCreate({ startOffset: data.startOffset, endOffset: data.endOffset, selectedText: data.selectedText, color: data.color as AnnotationColor })
        : undefined,
      onAnnotationClick,
    })
    return detach
  }, [isFullscreen, onAnnotationCreate, onAnnotationClick, fsPreviewHTML])

  // Apply highlights in fullscreen preview
  useEffect(() => {
    const el = fsPreviewRef.current
    if (!el || !window.GoWikiAnnotations) return
    window.GoWikiAnnotations.apply(el, fsAnnotationsVisible ? (annotations ?? []) : [], selectedAnnotationId)
  }, [fsPreviewHTML, annotations, selectedAnnotationId, fsAnnotationsVisible])

  // ── Keep contentRef in sync ──────────────────────────────────
  useEffect(() => { contentRef.current = content }, [content])

  // ── Load content from REST on mount ────────────────────────
  useEffect(() => {
    let cancelled = false
    apiClient.getWikiPageContent(page.id).then(res => {
      if (cancelled) return
      if (res.content) {
        setContent(res.content)
        lastSavedContentRef.current = res.content
      }
    }).catch(() => {
      // ignore — will fall back to Yjs or empty
    })
    return () => { cancelled = true }
  }, [page.id])

  // ── Manual save function ─────────────────────────────────────
  const saveNow = useCallback(async (manualSave = false) => {
    const current = contentRef.current
    if (isSavingRef.current || current === lastSavedContentRef.current) return

    isSavingRef.current = true
    setSaveStatus('saving')
    try {
      const result = await apiClient.updateWikiPageContent(page.id, current, manualSave)
      lastSavedContentRef.current = current
      isDirtyRef.current = false
      setSaveStatus('saved')
      setLastEditedBy(user?.name ?? null)
      setLastEditedAt(result.updated_at)
      setTimeout(() => setSaveStatus(clearSavedStatus), 3000)
    } catch {
      setSaveStatus('error')
    } finally {
      isSavingRef.current = false
    }
  }, [page.id, user?.name])

  useAutoSave(page.id, autoSaveEnabled, saveNow, isDirtyRef, contentRef, lastSavedContentRef)

  // ── Yjs setup ────────────────────────────────────────────────

  useEffect(() => {
    const ydoc = new Y.Doc()
    ydocRef.current = ydoc
    const ytext = ydoc.getText('content')

    const token = localStorage.getItem('token')
    if (!token) {
      // no auth token — cannot connect WebSocket
      setSyncState('disconnected')
      return
    }

    const wsProtocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:'
    const wsHost = window.location.host
    const wsUrl = `${wsProtocol}//${wsHost}/api/wiki/collab`

    const provider = new WebsocketProvider(wsUrl, `wiki-page-${page.id}`, ydoc, {
      params: { token },
      connect: true,
    })
    providerRef.current = provider

    provider.on('status', ({ status }: { status: string }) => {
      setSyncState(mapYjsStatus(status))
    })

    const updateContent = () => setContent(ytext.toString())
    ytext.observe(updateContent)
    updateContent()

    return () => {
      ytext.unobserve(updateContent)
      provider.destroy()
      ydoc.destroy()
    }
  }, [page.id])

  // ── Yjs sync helper ──────────────────────────────────────────

  const syncToYjs = useCallback((newContent: string) => {
    if (!ydocRef.current) return
    const ytext = ydocRef.current.getText('content')
    const currentContent = ytext.toString()
    if (newContent !== currentContent) {
      ydocRef.current.transact(() => {
        ytext.delete(0, currentContent.length)
        ytext.insert(0, newContent)
      })
    }
  }, [])

  const handleTextareaChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newContent = e.target.value
    setContent(newContent)
    syncToYjs(newContent)
    isDirtyRef.current = true
  }

  // ── Toolbar action dispatcher ────────────────────────────────

  const execToolbarAction = useCallback((action: ToolbarAction) => {
    const textarea = isFullscreen ? fsTextareaRef.current : textareaRef.current
    if (!textarea) return

    switch (action.action) {
      case 'wrap':
        insertAtCursor(textarea, action.before!, action.after!, content, setContent, syncToYjs, isDirtyRef)
        break
      case 'line':
        insertLine(textarea, action.prefix!, content, setContent, syncToYjs, isDirtyRef)
        break
      case 'insert': {
        const start = textarea.selectionStart
        const newContent = content.substring(0, start) + action.text! + content.substring(start)
        setContent(newContent)
        syncToYjs(newContent)
        isDirtyRef.current = true
        setTimeout(() => {
          textarea.focus()
          textarea.selectionStart = textarea.selectionEnd = start + action.text!.length
        }, 0)
        break
      }
    }
  }, [content, syncToYjs, isFullscreen])

  // ── Server-side preview (inline mode) ────────────────────────

  const loadPreview = useCallback(async (markdown: string) => {
    const html = await abortAndFetchPreview(abortRef, markdown)
    if (html !== null) setPreviewHTML(html)
  }, [])

  useEffect(() => {
    if (isPreview) loadPreview(content)
  }, [isPreview, content, loadPreview])

  // ── Fullscreen live preview (debounced) ──────────────────────

  const scheduleFsPreview = useCallback((markdown: string) => {
    if (previewTimerRef.current) clearTimeout(previewTimerRef.current)
    previewTimerRef.current = setTimeout(async () => {
      const html = await abortAndFetchPreview(abortRef, markdown)
      if (html !== null) setFsPreviewHTML(html)
    }, PREVIEW_DEBOUNCE_MS)
  }, [])

  // When fullscreen opens, render preview immediately; schedule on content change
  useEffect(() => {
    if (isFullscreen) scheduleFsPreview(content)
  }, [isFullscreen, content, scheduleFsPreview])

  // ── Init draw embeds in previews ──────────────────────────────

  const previewUpdateContent = useCallback((newContent: string) => {
    setContent(newContent)
    syncToYjs(newContent)
    isDirtyRef.current = true
  }, [syncToYjs])

  const figmaCleanupRef = useRef<() => void>(() => {})
  const fsFigmaCleanupRef = useRef<() => void>(() => {})

  useEffect(() => {
    if (isPreview && previewHTML) {
      const t = setTimeout(() => {
        initDrawEmbeds(previewRef.current, contentRef, previewUpdateContent)
        addImageEditOverlays(previewRef.current, contentRef, previewUpdateContent)
        figmaCleanupRef.current()
        figmaCleanupRef.current = initFigmaEmbeds(previewRef.current)
      }, 50)
      return () => { clearTimeout(t); figmaCleanupRef.current() }
    }
  }, [isPreview, previewHTML, previewUpdateContent])

  useEffect(() => {
    if (isFullscreen && fsPreviewHTML) {
      const t = setTimeout(() => {
        initDrawEmbeds(fsPreviewRef.current, contentRef, previewUpdateContent)
        addImageEditOverlays(fsPreviewRef.current, contentRef, previewUpdateContent)
        fsFigmaCleanupRef.current()
        fsFigmaCleanupRef.current = initFigmaEmbeds(fsPreviewRef.current)
      }, 50)
      return () => { clearTimeout(t); fsFigmaCleanupRef.current() }
    }
  }, [isFullscreen, fsPreviewHTML, previewUpdateContent])

  // ── Mermaid diagram rendering ─────────────────────────────────
  useEffect(() => {
    if (previewRef.current) window.GoWikiMermaid?.run(previewRef.current)
  }, [previewHTML])

  useEffect(() => {
    if (fsPreviewRef.current) window.GoWikiMermaid?.run(fsPreviewRef.current)
  }, [fsPreviewHTML])

  // Handle clicks on graph link chips rendered in preview HTML.
  useEffect(() => {
    const containers = [previewRef.current, fsPreviewRef.current].filter(Boolean)
    if (containers.length === 0) return

    const handleClick = (e: MouseEvent) => {
      const el = (e.target as Element).closest('[data-graph-type]') as HTMLElement | null
      if (!el) return
      e.preventDefault()
      const type = el.dataset.graphType
      const entityId = el.dataset.entityId
      if (!type || !entityId) return
      if (type === 'wiki') {
        navigate(`/app/projects/${page.project_id}?tab=wiki&page=${entityId}`)
      } else if (type === 'task') {
        navigate(`/app/projects/${page.project_id}`)
      }
    }

    containers.forEach(c => c?.addEventListener('click', handleClick))
    return () => containers.forEach(c => c?.removeEventListener('click', handleClick))
  }, [previewHTML, fsPreviewHTML, navigate, page.project_id])

  // ── Keyboard shortcuts ───────────────────────────────────────

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    switch (e.key) {
      case 'Tab': {
        e.preventDefault()
        const textarea = e.currentTarget
        const start = textarea.selectionStart
        const end = textarea.selectionEnd
        const newContent = content.substring(0, start) + '  ' + content.substring(end)
        setContent(newContent)
        syncToYjs(newContent)
        isDirtyRef.current = true
        setTimeout(() => { textarea.selectionStart = textarea.selectionEnd = start + 2 }, 0)
        break
      }
      case 'F11':
        e.preventDefault()
        setIsFullscreen(prev => !prev)
        break
      case 'Escape':
        if (isFullscreen) { e.preventDefault(); setIsFullscreen(false) }
        break
    }
  }, [content, syncToYjs, isFullscreen])

  // ── Double-click draw shortcode → open editor ─────────────

  const handleDoubleClick = useCallback((e: React.MouseEvent<HTMLTextAreaElement>) => {
    const drawId = findDrawShortcodeAtPosition(e.currentTarget.value, e.currentTarget.selectionStart)
    if (drawId) window.open(`/draw/${drawId}/edit`, '_blank')
  }, [])

  useGlobalKeyboard(isFullscreen, setIsFullscreen)

  // ── Fullscreen divider resize ────────────────────────────────

  const handleDividerMouseDown = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    const container = fsContainerRef.current
    if (!container) return

    const onMove = (ev: MouseEvent) => {
      const rect = container.getBoundingClientRect()
      const pct = ((ev.clientX - rect.left) / rect.width) * 100
      setFsSplitPct(Math.max(20, Math.min(80, pct)))
    }
    const onUp = () => {
      document.removeEventListener('mousemove', onMove)
      document.removeEventListener('mouseup', onUp)
    }
    document.addEventListener('mousemove', onMove)
    document.addEventListener('mouseup', onUp)
  }, [])

  // ── Image picker ─────────────────────────────────────────────

  const insertImageMarkdown = (alt: string, url: string, caption?: string, size?: string) => {
    const markup = buildImageMarkup(url, alt, caption || '', size || 'm')
    const textarea = isFullscreen ? fsTextareaRef.current : textareaRef.current
    const { newContent, focusPos } = insertMarkupAtCursor(textarea, content, markup)
    setContent(newContent)
    syncToYjs(newContent)
    isDirtyRef.current = true
    if (focusPos !== null && textarea) {
      setTimeout(() => { textarea.selectionStart = textarea.selectionEnd = focusPos; textarea.focus() }, 0)
    }
    setShowImagePicker(false)
  }

  const { isDragOver, isDropUploading, handleDragEnter, handleDragOver, handleDragLeave, handleDrop } =
    useImageDrop({ pageId: page.id, isFullscreen, content, setContent, syncToYjs, isDirtyRef, textareaRef, fsTextareaRef })

  const {
    editImgList, selectedEditImg, editAlt, editCaption, editSize,
    handleEditImg, selectImgForEdit, saveEditImg,
    setEditAlt, setEditCaption, setEditSize, deselectImg, closeEditImg,
  } = useImageEdit({ content, setContent, syncToYjs, isDirtyRef })

  const {
    showDrawBrowser, drawList, drawLoading,
    editDrawList, selectedEditDraw, editDrawSize, editDrawZoom,
    handleDraw, handleDrawInsert, handleDrawRename, handleDrawDelete,
    handleDrawNew, handleDrawDeleteUnused, handleEditDraw, selectDrawForEdit, saveEditDraw,
    setEditDrawSize, setEditDrawZoom, closeDrawBrowser, closeEditDraw,
  } = useDrawBrowser({ content, setContent, syncToYjs, isDirtyRef, isFullscreen, textareaRef, fsTextareaRef, projectId: page.project_id })

  const handleFigmaInsert = useCallback(() => {
    const url = figmaInputUrl.trim()
    if (!url) {
      setFigmaInputError('URL is required')
      return
    }
    if (!/figma\.com\/(file|design|proto)\//.test(url)) {
      setFigmaInputError('Must be a Figma file, design, or prototype URL')
      return
    }
    const shortcode = buildFigmaShortcode(url)
    const ta = isFullscreen ? fsTextareaRef.current : textareaRef.current
    const { newContent, focusPos } = insertMarkupAtCursor(ta, content, shortcode + '\n')
    setContent(newContent)
    syncToYjs(newContent)
    isDirtyRef.current = true
    if (focusPos !== null && ta) {
      ta.focus()
      ta.setSelectionRange(focusPos, focusPos)
    }
    setFigmaInputUrl('')
    setFigmaInputError('')
    setShowFigmaInput(false)
  }, [figmaInputUrl, content, setContent, syncToYjs, isDirtyRef, isFullscreen, textareaRef, fsTextareaRef])

  // ── Toolbar JSX ──────────────────────────────────────────────

  const renderToolbar = (compact?: boolean) => (
    <div className={`flex items-center gap-1 ${compact ? '' : 'flex-wrap'}`}>
      {toolbarActions.map((action) => (
        <button
          key={action.label}
          onClick={() => execToolbarAction(action)}
          className="px-2 py-1 rounded text-xs font-mono font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80 hover:text-dark-text-primary"
          title={action.title}
        >
          {action.icon}
        </button>
      ))}
      <button
        onClick={() => setShowImagePicker(true)}
        className="px-2 py-1 rounded text-xs font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80 hover:text-dark-text-primary flex items-center gap-1"
        title="Insert image"
      >
        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
      </button>
      <button
        onClick={handleEditImg}
        className="px-2 py-1 rounded text-xs font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80 hover:text-dark-text-primary flex items-center gap-1"
        title="Edit image in content"
      >
        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
        </svg>
      </button>
      <button
        onClick={handleDraw}
        className="px-2 py-1 rounded text-xs font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80 hover:text-dark-text-primary flex items-center gap-1"
        title="Browse drawings"
      >
        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
          <path d="M12 19l7-7 3 3-7 7-3-3z" />
          <path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z" />
          <path d="M2 2l7.586 7.586" />
          <circle cx="11" cy="11" r="2" />
        </svg>
        Draw
      </button>
      <button
        onClick={handleEditDraw}
        className="px-2 py-1 rounded text-xs font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80 hover:text-dark-text-primary flex items-center gap-1"
        title="Edit existing draw shortcode"
      >
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24">
          <path d="M12 19l7-7 3 3-7 7-3-3z" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round" />
          <path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round" />
          <path d="M15.5 6.5l2 2" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round" />
        </svg>
      </button>
      <button
        onClick={() => { setShowFigmaInput(v => !v); setFigmaInputError('') }}
        className={`px-2 py-1 rounded text-xs font-medium transition-colors flex items-center gap-1 ${showFigmaInput ? 'bg-primary-500/20 text-primary-400' : 'bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80 hover:text-dark-text-primary'}`}
        title="Insert Figma embed"
      >
        <svg width="12" height="12" viewBox="0 0 38 57" fill="none" aria-hidden="true">
          <path d="M19 28.5c0-2.674 1.054-5.239 2.929-7.114C23.804 19.51 26.37 18.457 29.043 18.457s5.239 1.053 7.115 2.929c1.875 1.875 2.929 4.44 2.929 7.114s-1.054 5.239-2.929 7.115C34.282 37.49 31.717 38.543 29.043 38.543s-5.239-1.053-7.114-2.928C20.054 33.739 19 31.174 19 28.5z" fill="#1ABCFE"/>
          <path d="M-1.087 47.543c0-2.674 1.053-5.239 2.929-7.114C3.717 38.554 6.283 37.5 8.956 37.5H19v10.043c0 2.674-1.053 5.239-2.929 7.115C14.196 56.533 11.63 57.587 8.957 57.587s-5.239-1.054-7.115-2.929C-.033 52.783-1.087 50.217-1.087 47.543z" fill="#0ACF83"/>
          <path d="M19 .413V18.457h10.043c2.674 0 5.239-1.053 7.115-2.929 1.875-1.875 2.929-4.44 2.929-7.114S38.033 3.174 36.158 1.298C34.282-.577 31.717-1.63 29.043-1.63H19V.413z" fill="#FF7262"/>
          <path d="M-1.087 8.413c0 2.674 1.053 5.239 2.929 7.115C3.717 17.403 6.283 18.457 8.956 18.457H19V-1.587H8.956c-2.673 0-5.239 1.054-7.114 2.929C-.033 3.217-1.087 5.74-1.087 8.413z" fill="#F24E1E"/>
          <path d="M-1.087 28.5c0 2.674 1.053 5.239 2.929 7.115C3.717 37.49 6.283 38.543 8.956 38.543H19V18.457H8.956c-2.673 0-5.239 1.053-7.114 2.929C-.033 23.261-1.087 25.826-1.087 28.5z" fill="#A259FF"/>
        </svg>
        Figma
      </button>
    </div>
  )

  // ── Version history handlers ──────────────────────────────────

  const openVersionHistory = useCallback(async () => {
    setShowVersionHistory(true)
    setVersionsLoading(true)
    setViewingVersion(null)
    try {
      const data = await apiClient.getWikiPageVersions(page.id)
      setVersions(data)
    } catch {
      setVersions([])
    } finally {
      setVersionsLoading(false)
    }
  }, [page.id])

  const viewVersion = useCallback(async (versionNumber: number) => {
    try {
      const data = await apiClient.getWikiPageVersion(page.id, versionNumber)
      setViewingVersion(data)
    } catch {
      // ignore
    }
  }, [page.id])

  const restoreVersion = useCallback(async (versionNumber: number) => {
    try {
      const data = await apiClient.restoreWikiPageVersion(page.id, versionNumber)
      setContent(data.content)
      contentRef.current = data.content
      lastSavedContentRef.current = data.content
      isDirtyRef.current = false
      setShowVersionHistory(false)
      setViewingVersion(null)
      setSaveStatus('saved')
      setLastEditedBy(user?.name ?? null)
      setLastEditedAt(data.updated_at)
      setTimeout(() => setSaveStatus(clearSavedStatus), 3000)
    } catch {
      // ignore
    }
  }, [page.id, user?.name])

  // ── Fullscreen overlay ───────────────────────────────────────

  // ── Fullscreen overlay ───────────────────────────────────────

  const fullscreenContent = isFullscreen && (
    <div className="fixed inset-0 z-50 bg-dark-bg-primary flex flex-col">
      {/* Top bar */}
      <div className="flex items-center justify-between border-b border-dark-border-subtle bg-dark-bg-secondary px-4 py-2">
        <div className="flex items-center gap-4">
          <span className="text-sm font-semibold text-dark-text-primary truncate max-w-xs">
            {page.title}
          </span>
          {renderToolbar(true)}
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${getSaveStatusColor(saveStatus, syncState)}`} />
            <span className="text-xs text-dark-text-tertiary">
              {getSaveStatusText(saveStatus, autoSaveEnabled)}
            </span>
          </div>
          <button
            onClick={() => setAutoSaveEnabled(prev => !prev)}
            className={`px-2 py-1 rounded text-xs font-medium transition-colors ${
              autoSaveEnabled
                ? 'bg-green-500/15 text-green-400 hover:bg-green-500/25'
                : 'bg-dark-bg-tertiary text-dark-text-tertiary hover:bg-dark-bg-tertiary/80'
            }`}
            title={autoSaveEnabled ? 'Disable autosave' : 'Enable autosave'}
          >
            {autoSaveEnabled ? 'Auto' : 'Manual'}
          </button>
          <button
            onClick={() => saveNow(true)}
            disabled={saveStatus === 'saving'}
            className="px-2.5 py-1 rounded text-xs font-medium transition-colors bg-primary-600 text-white hover:bg-primary-500 disabled:opacity-50"
            title="Save now"
          >
            Save
          </button>
          {onAnnotationUpdate && (
            <button
              onClick={() => setFsAnnotationsVisible(v => !v)}
              className={`px-2.5 py-1 rounded text-xs font-medium transition-colors ${
                fsAnnotationsVisible
                  ? 'bg-primary-500/20 text-primary-400 hover:bg-primary-500/30'
                  : 'bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80'
              }`}
              title="Toggle annotations"
            >
              <svg className="w-3.5 h-3.5 inline mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
              </svg>
              Annotations
              {(annotations ?? []).filter(a => !a.resolved).length > 0 && (
                <span className="ml-1 px-1 py-0.5 bg-primary-500/30 text-primary-300 rounded-full text-xs">
                  {(annotations ?? []).filter(a => !a.resolved).length}
                </span>
              )}
            </button>
          )}
          <button
            onClick={() => setIsFullscreen(false)}
            className="px-3 py-1.5 rounded text-xs font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-red-500/20 hover:text-red-400"
            title="Exit fullscreen (Esc)"
          >
            Exit
          </button>
        </div>
      </div>

      {/* Figma URL input bar (fullscreen) */}
      {showFigmaInput && (
        <div className="flex items-center gap-2 px-4 py-1.5 border-b border-dark-border-subtle bg-dark-bg-tertiary/30 flex-shrink-0">
          <input
            type="url"
            value={figmaInputUrl}
            onChange={e => { setFigmaInputUrl(e.target.value); setFigmaInputError('') }}
            onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); handleFigmaInsert() } if (e.key === 'Escape') { setShowFigmaInput(false); setFigmaInputError('') } }}
            placeholder="https://www.figma.com/file/..."
            className="flex-1 bg-dark-bg-primary border border-dark-border-subtle rounded px-2 py-1 text-xs text-dark-text-primary placeholder-dark-text-tertiary focus:outline-none focus:border-primary-500"
            autoFocus
          />
          <button onClick={handleFigmaInsert} className="px-2 py-1 rounded text-xs font-medium bg-primary-600 text-white hover:bg-primary-500 transition-colors">Insert</button>
          <button onClick={() => { setShowFigmaInput(false); setFigmaInputError('') }} className="px-2 py-1 rounded text-xs font-medium bg-dark-bg-tertiary text-dark-text-secondary hover:text-dark-text-primary transition-colors">Cancel</button>
          {figmaInputError && <span className="text-xs text-red-400">{figmaInputError}</span>}
        </div>
      )}

      {/* Split panes + optional annotation sidebar */}
      <div className="flex flex-1 overflow-hidden">
      <div ref={fsContainerRef} className="flex flex-1 overflow-hidden">
        {/* Left: editor */}
        <section
          aria-label="Editor with drop support"
          style={{ width: `${fsSplitPct}%` }}
          className="flex flex-col overflow-hidden relative"
          onDragEnter={handleDragEnter}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          <textarea
            ref={fsTextareaRef}
            value={content}
            onChange={handleTextareaChange}
            onKeyDown={handleKeyDown}
            onDoubleClick={handleDoubleClick}
            className="flex-1 w-full bg-dark-bg-primary text-dark-text-primary resize-none focus:outline-none font-mono text-sm p-4"
            spellCheck={false}
            placeholder="Start writing in Markdown..."
          />
          <DropOverlay isDragOver={isDragOver} isDropUploading={isDropUploading} />
        </section>

        {/* Divider */}
        <button
          type="button"
          ref={dividerRef}
          onMouseDown={handleDividerMouseDown}
          className="w-1.5 bg-dark-border-subtle hover:bg-dark-accent-primary/50 cursor-col-resize transition-colors flex-shrink-0 border-0 p-0"
          aria-label="Resize panels"
        />

        {/* Right: live preview */}
        <div style={{ width: `${100 - fsSplitPct}%` }} className="overflow-y-auto p-4">
          <PreviewContent previewHTML={fsPreviewHTML} content={content} previewRef={fsPreviewRef} />
        </div>
      </div>
      {/* Fullscreen annotation sidebar */}
      {fsAnnotationsVisible && onAnnotationUpdate && onAnnotationDelete && onCommentCreate && onCommentUpdate && onCommentDelete && (
        <div className="w-80 flex-shrink-0 border-l border-dark-border-subtle flex flex-col overflow-hidden">
          <WikiAnnotationSidebar
            annotations={annotations ?? []}
            selectedAnnotationId={selectedAnnotationId ?? null}
            showResolved={showResolved}
            projectId={page.project_id}
            onAnnotationSelect={(id) => onAnnotationClick?.(id ?? 0)}
            onAnnotationUpdate={onAnnotationUpdate}
            onAnnotationDelete={onAnnotationDelete}
            onCommentCreate={onCommentCreate}
            onCommentUpdate={onCommentUpdate}
            onCommentDelete={onCommentDelete}
            onToggleShowResolved={onToggleShowResolved ?? (() => {})}
          />
        </div>
      )}
      </div>
    </div>
  )

  // ── Render ───────────────────────────────────────────────────

  return (
    <>
      {fullscreenContent}

      {!isFullscreen && (
        <div className="flex flex-col h-full">
          {/* Header */}
          <div className="border-b border-dark-border-subtle bg-dark-bg-secondary px-6 py-4">
            <div className="flex items-center justify-between">
              <div>
                <h1 className="text-2xl font-semibold text-dark-text-primary">{page.title}</h1>
                <div className="flex items-center gap-2 mt-1 text-xs text-dark-text-tertiary">
                  {page.creator_name && (
                    <span>Created by{' '}
                      <Link to={`/app/users/${page.created_by}`} className="text-dark-text-secondary hover:text-primary-400 transition-colors">
                        {page.creator_name}
                      </Link>
                      {' '}· {new Date(page.created_at).toLocaleDateString()}
                    </span>
                  )}
                  {(lastEditedBy || lastEditedAt) && (
                    <>
                      <span className="text-dark-border-subtle">·</span>
                      <span>
                        Last edited{lastEditedBy ? <> by{' '}
                          <Link to={`/app/users/${page.updated_by ?? page.created_by}`} className="text-dark-text-secondary hover:text-primary-400 transition-colors">
                            {lastEditedBy}
                          </Link>
                        </> : ''}{' '}
                        · {new Date(lastEditedAt).toLocaleString()}
                      </span>
                    </>
                  )}
                </div>
                <div className="flex items-center gap-3 mt-2">
                  <div className="flex items-center gap-2">
                    <div className={`w-2 h-2 rounded-full ${getSaveStatusColor(saveStatus, syncState)}`} />
                    <span className="text-sm text-dark-text-tertiary">
                      {getSaveStatusText(saveStatus, autoSaveEnabled)}
                    </span>
                  </div>
                  <button
                    onClick={() => setAutoSaveEnabled(prev => !prev)}
                    className={`px-2 py-0.5 rounded text-xs font-medium transition-colors ${
                      autoSaveEnabled
                        ? 'bg-green-500/15 text-green-400 hover:bg-green-500/25'
                        : 'bg-dark-bg-tertiary text-dark-text-tertiary hover:bg-dark-bg-tertiary/80'
                    }`}
                    title={autoSaveEnabled ? 'Disable autosave' : 'Enable autosave'}
                  >
                    {autoSaveEnabled ? 'Auto' : 'Manual'}
                  </button>
                  <button
                    onClick={() => saveNow(true)}
                    disabled={saveStatus === 'saving'}
                    className="px-2.5 py-0.5 rounded text-xs font-medium transition-colors bg-primary-600 text-white hover:bg-primary-500 disabled:opacity-50"
                    title="Save now"
                  >
                    Save
                  </button>
                </div>
              </div>

              <div className="flex items-center gap-2">
                <button
                  onClick={() => setIsPreview(false)}
                  className={`px-4 py-2 rounded text-sm font-medium transition-colors ${
                    !isPreview
                      ? 'bg-dark-accent-primary text-white'
                      : 'bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80'
                  }`}
                >
                  Edit
                </button>
                <button
                  onClick={() => setIsPreview(true)}
                  className={`px-4 py-2 rounded text-sm font-medium transition-colors ${
                    isPreview
                      ? 'bg-dark-accent-primary text-white'
                      : 'bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80'
                  }`}
                >
                  Preview
                </button>
                <button
                  onClick={openVersionHistory}
                  className="px-3 py-2 rounded text-sm font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80"
                  title="Version history"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </button>
                <button
                  onClick={() => setIsFullscreen(true)}
                  className="px-3 py-2 rounded text-sm font-medium transition-colors bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80"
                  title="Fullscreen editor (F11)"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                  </svg>
                </button>
              </div>
            </div>
          </div>

          {/* Toolbar (edit mode only) */}
          {!isPreview && (
            <div className="border-b border-dark-border-subtle bg-dark-bg-secondary">
              <div className="px-6 py-2">{renderToolbar()}</div>
              {showFigmaInput && (
                <div className="flex items-center gap-2 px-6 py-1.5 border-t border-dark-border-subtle bg-dark-bg-tertiary/30">
                  <input
                    type="url"
                    value={figmaInputUrl}
                    onChange={e => { setFigmaInputUrl(e.target.value); setFigmaInputError('') }}
                    onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); handleFigmaInsert() } if (e.key === 'Escape') { setShowFigmaInput(false); setFigmaInputError('') } }}
                    placeholder="https://www.figma.com/file/..."
                    className="flex-1 bg-dark-bg-primary border border-dark-border-subtle rounded px-2 py-1 text-xs text-dark-text-primary placeholder-dark-text-tertiary focus:outline-none focus:border-primary-500"
                    autoFocus
                  />
                  <button onClick={handleFigmaInsert} className="px-2 py-1 rounded text-xs font-medium bg-primary-600 text-white hover:bg-primary-500 transition-colors">Insert</button>
                  <button onClick={() => { setShowFigmaInput(false); setFigmaInputError('') }} className="px-2 py-1 rounded text-xs font-medium bg-dark-bg-tertiary text-dark-text-secondary hover:text-dark-text-primary transition-colors">Cancel</button>
                  {figmaInputError && <span className="text-xs text-red-400">{figmaInputError}</span>}
                </div>
              )}
            </div>
          )}

          {/* Content */}
          <div className="flex-1 overflow-hidden flex flex-col">
            {isPreview ? (
              <div className="h-full overflow-y-auto px-6 py-4">
                <PreviewContent previewHTML={previewHTML} content={content} previewRef={previewRef} />
              </div>
            ) : (
              <>
                <section
                  aria-label="Editor with drop support"
                  className="relative flex-1 min-h-0"
                  onDragEnter={handleDragEnter}
                  onDragOver={handleDragOver}
                  onDragLeave={handleDragLeave}
                  onDrop={handleDrop}
                >
                  <textarea
                    ref={textareaRef}
                    value={content}
                    onChange={handleTextareaChange}
                    onKeyDown={handleKeyDown}
                    onDoubleClick={handleDoubleClick}
                    placeholder="Start writing in Markdown...

# Heading 1
## Heading 2

**bold** *italic* `code`

- List item
- List item

[Link text](https://example.com)

```code block```"
                    className="w-full h-full px-6 py-4 bg-dark-bg-primary text-dark-text-primary resize-none focus:outline-none font-mono text-sm placeholder-dark-text-tertiary/50"
                    spellCheck={false}
                  />
                  <DropOverlay isDragOver={isDragOver} isDropUploading={isDropUploading} />
                </section>
                {/* Visible drop zone */}
                <section
                  aria-label="Drop zone for images"
                  className={`mx-6 mb-4 mt-2 border-2 border-dashed rounded-lg p-4 flex items-center justify-center gap-3 transition-colors ${
                    isDragOver
                      ? 'border-primary-500 bg-primary-500/5'
                      : 'border-dark-border-subtle hover:border-primary-500/50'
                  }`}
                  onDragEnter={handleDragEnter}
                  onDragOver={handleDragOver}
                  onDragLeave={handleDragLeave}
                  onDrop={handleDrop}
                >
                  <svg className="w-8 h-8 text-dark-text-tertiary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                  </svg>
                  <div>
                    <div className="text-sm text-dark-text-secondary">
                      Drop images here or{' '}
                      <button
                        onClick={() => setShowImagePicker(true)}
                        className="text-primary-400 hover:underline font-medium"
                      >
                        browse
                      </button>
                    </div>
                    <div className="text-xs text-dark-text-tertiary">Supports JPG, PNG, GIF</div>
                  </div>
                </section>
              </>
            )}
          </div>

          {/* Footer helper */}
          {!isPreview && (
            <div className="border-t border-dark-border-subtle bg-dark-bg-secondary px-6 py-2">
              <div className="flex items-center gap-4 text-xs text-dark-text-tertiary">
                <span>Markdown supported</span>
                <span>&bull;</span>
                <span className={getSaveStatusTextColor(saveStatus)}>
                  {getSaveStatusText(saveStatus, autoSaveEnabled)}
                </span>
                <span>&bull;</span>
                <span>Tab to indent</span>
                <span>&bull;</span>
                <span>F11 fullscreen</span>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Shared modals — rendered once regardless of fullscreen state */}
      {showImagePicker && (
        <ImagePickerModal
          onSelect={insertImageMarkdown}
          onClose={() => setShowImagePicker(false)}
          projectId={page.project_id}
          wikiPageId={page.id}
          onUploadComplete={() => {}}
        />
      )}

      <EditImageModal
        editImgList={editImgList}
        selectedEditImg={selectedEditImg}
        editAlt={editAlt}
        editCaption={editCaption}
        editSize={editSize}
        onSelectImg={selectImgForEdit}
        onAltChange={setEditAlt}
        onCaptionChange={setEditCaption}
        onSizeChange={setEditSize}
        onSave={saveEditImg}
        onDeselect={deselectImg}
        onClose={closeEditImg}
      />

      {showDrawBrowser && (
        <DrawBrowserModal
          drawings={drawList}
          loading={drawLoading}
          editorContent={content}
          onInsert={handleDrawInsert}
          onRename={handleDrawRename}
          onDelete={handleDrawDelete}
          onDeleteUnused={handleDrawDeleteUnused}
          onNew={handleDrawNew}
          onClose={closeDrawBrowser}
        />
      )}

      {editDrawList && (
        <EditDrawModal
          draws={editDrawList}
          selectedDraw={selectedEditDraw}
          editSize={editDrawSize}
          editZoom={editDrawZoom}
          onSelect={selectDrawForEdit}
          onSizeChange={setEditDrawSize}
          onZoomChange={setEditDrawZoom}
          onSave={saveEditDraw}
          onClose={closeEditDraw}
        />
      )}

      {/* Version History Panel */}
      {showVersionHistory && (
        <div className="fixed inset-0 z-50 flex">
          {/* Backdrop */}
          <div
            className="absolute inset-0 bg-black/40"
            onClick={() => { setShowVersionHistory(false); setViewingVersion(null) }}
            aria-hidden="true"
          />
          {/* Panel */}
          <div className="relative ml-auto w-full max-w-2xl bg-dark-bg-secondary border-l border-dark-border-subtle flex flex-col h-full shadow-2xl">
            {/* Panel header */}
            <div className="flex items-center justify-between px-5 py-4 border-b border-dark-border-subtle">
              <h2 className="text-base font-semibold text-dark-text-primary">Version History</h2>
              <button
                onClick={() => { setShowVersionHistory(false); setViewingVersion(null) }}
                className="text-dark-text-tertiary hover:text-dark-text-primary transition-colors"
                aria-label="Close version history"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            {viewingVersion ? (
              /* Version diff view */
              <div className="flex flex-col flex-1 overflow-hidden">
                <div className="flex items-center gap-3 px-5 py-3 border-b border-dark-border-subtle">
                  <button
                    onClick={() => setViewingVersion(null)}
                    className="text-xs text-primary-400 hover:underline"
                  >
                    ← Back to list
                  </button>
                  <span className="text-xs text-dark-text-tertiary">
                    Version {viewingVersion.version_number} — {new Date(viewingVersion.created_at).toLocaleString()}
                  </span>
                  <button
                    onClick={() => restoreVersion(viewingVersion.version_number)}
                    className="ml-auto px-3 py-1 rounded text-xs font-medium bg-primary-600 text-white hover:bg-primary-500 transition-colors"
                  >
                    Restore this version
                  </button>
                </div>
                <div className="flex flex-1 overflow-hidden divide-x divide-dark-border-subtle">
                  <div className="flex-1 flex flex-col overflow-hidden">
                    <div className="px-3 py-2 text-xs font-medium text-dark-text-tertiary bg-dark-bg-tertiary/30">This version</div>
                    <pre className="flex-1 overflow-auto px-3 py-2 text-xs text-dark-text-secondary font-mono whitespace-pre-wrap break-words">
                      {viewingVersion.content || <span className="text-dark-text-tertiary italic">Empty</span>}
                    </pre>
                  </div>
                  <div className="flex-1 flex flex-col overflow-hidden">
                    <div className="px-3 py-2 text-xs font-medium text-dark-text-tertiary bg-dark-bg-tertiary/30">Current</div>
                    <pre className="flex-1 overflow-auto px-3 py-2 text-xs text-dark-text-secondary font-mono whitespace-pre-wrap break-words">
                      {content || <span className="text-dark-text-tertiary italic">Empty</span>}
                    </pre>
                  </div>
                </div>
              </div>
            ) : (
              /* Version list */
              <div className="flex-1 overflow-y-auto">
                {versionsLoading ? (
                  <div className="flex items-center justify-center py-12 text-dark-text-tertiary text-sm">
                    Loading versions…
                  </div>
                ) : versions.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-12 text-dark-text-tertiary text-sm gap-2">
                    <svg className="w-8 h-8 opacity-40" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    <span>No versions yet. Save the page to create a version.</span>
                  </div>
                ) : (
                  <ul className="divide-y divide-dark-border-subtle">
                    {versions.map((v) => (
                      <li key={v.id} className="flex items-center gap-3 px-5 py-3 hover:bg-dark-bg-tertiary/30 transition-colors">
                        <div className="flex-1 min-w-0">
                          <div className="text-sm font-medium text-dark-text-primary">Version {v.version_number}</div>
                          <div className="text-xs text-dark-text-tertiary">
                            {new Date(v.created_at).toLocaleString()}
                            {v.creator_name ? ` · ${v.creator_name}` : ''}
                          </div>
                        </div>
                        <button
                          onClick={() => viewVersion(v.version_number)}
                          className="px-2.5 py-1 rounded text-xs font-medium bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-primary/50 transition-colors"
                        >
                          View
                        </button>
                        <button
                          onClick={() => restoreVersion(v.version_number)}
                          className="px-2.5 py-1 rounded text-xs font-medium bg-primary-600/20 text-primary-400 hover:bg-primary-600/30 transition-colors"
                        >
                          Restore
                        </button>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            )}
          </div>
        </div>
      )}
    </>
  )
}

// ── DrawCard sub-component ───────────────────────────────────────

function DrawCard({ drawing, isUsed, onInsert, onRename, onDelete }: Readonly<{
  drawing: DrawItem
  isUsed: boolean
  onInsert: (id: string, size: string, zoom: string) => void
  onRename: (id: string, title: string) => void
  onDelete: (id: string) => void
}>) {
  const [editing, setEditing] = useState(false)
  const [title, setTitle] = useState(drawing.title || 'Untitled')
  const [size, setSize] = useState('m')
  const [zoom, setZoom] = useState('fit')
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    if (editing && inputRef.current) inputRef.current.focus()
  }, [editing])

  const saveTitle = () => {
    const trimmed = title.trim()
    if (trimmed && trimmed !== drawing.title) {
      onRename(drawing.id, trimmed)
    } else {
      setTitle(drawing.title || 'Untitled')
    }
    setEditing(false)
  }

  const formattedDate = (() => {
    try {
      return new Date(drawing.updated_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })
    } catch { return drawing.updated_at }
  })()

  return (
    <div
      className={`border rounded-xl p-4 flex flex-col gap-1.5 transition-colors ${isUsed ? 'border-green-500/30 hover:border-green-500/50' : 'border-dark-border-subtle hover:border-primary-500/50'}`}
    >
      <div className="flex items-center gap-1.5">
        {editing ? (
          <input
            ref={inputRef}
            value={title}
            onChange={e => setTitle(e.target.value)}
            onBlur={saveTitle}
            onKeyDown={e => {
              if (e.key === 'Enter') saveTitle()
              if (e.key === 'Escape') { setTitle(drawing.title || 'Untitled'); setEditing(false) }
            }}
            className="text-sm font-semibold text-dark-text-primary bg-dark-bg-tertiary border border-primary-500 rounded px-2 py-1 focus:outline-none flex-1 min-w-0"
          />
        ) : (
          <button
            onClick={(e) => { e.stopPropagation(); setEditing(true) }}
            className="text-sm font-semibold text-dark-text-primary text-left truncate hover:text-primary-400 transition-colors flex-1 min-w-0"
            title="Click to rename"
          >
            {drawing.title || 'Untitled'}
          </button>
        )}
        {isUsed && (
          <span className="text-[10px] font-semibold text-green-400 bg-green-500/10 px-1.5 py-0.5 rounded flex-shrink-0">in use</span>
        )}
      </div>
      <span className="text-xs text-dark-text-tertiary">{formattedDate}</span>
      <div className="flex gap-1.5 mt-1 items-center" role="toolbar" onClick={e => e.stopPropagation()} onKeyDown={e => e.stopPropagation()}>
        <SearchSelect
          variant="inline"
          value={size}
          onChange={setSize}
          options={[
            { value: 's', label: 'S' },
            { value: 'm', label: 'M' },
            { value: 'l', label: 'L' },
          ]}
        />
        <SearchSelect
          variant="inline"
          value={zoom}
          onChange={setZoom}
          options={[
            { value: 'fit', label: 'fit' },
            { value: '50%', label: '50%' },
            { value: '100%', label: '100%' },
            { value: '150%', label: '150%' },
            { value: '200%', label: '200%' },
          ]}
        />
        <button
          onClick={(e) => { e.stopPropagation(); window.open(`/draw/${drawing.id}/edit`, '_blank') }}
          className="w-[26px] h-[26px] rounded flex items-center justify-center bg-dark-bg-tertiary text-dark-text-secondary hover:bg-dark-bg-tertiary/80 hover:text-dark-text-primary transition-colors"
          title="Edit drawing"
        >
          <svg className="w-3.5 h-3.5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
            <path d="M17 3a2.828 2.828 0 114 4L7.5 20.5 2 22l1.5-5.5L17 3z"/>
          </svg>
        </button>
        <button
          onClick={(e) => { e.stopPropagation(); onDelete(drawing.id) }}
          className="w-[26px] h-[26px] rounded flex items-center justify-center bg-red-500/15 text-red-400 hover:bg-red-500/25 transition-colors"
          title="Delete drawing"
        >
          <svg className="w-3.5 h-3.5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
            <polyline points="3 6 5 6 21 6"/>
            <path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/>
          </svg>
        </button>
      </div>
      <button
        onClick={() => onInsert(drawing.id, size, zoom)}
        className="mt-1.5 w-full py-1.5 rounded-lg text-xs font-medium bg-primary-500/10 text-primary-400 hover:bg-primary-500/20 transition-colors"
      >
        Insert
      </button>
    </div>
  )
}

// ── DrawBrowserModal ─────────────────────────────────────────────

function DrawBrowserModal({ drawings, loading, editorContent, onInsert, onRename, onDelete, onDeleteUnused, onNew, onClose }: Readonly<{
  drawings: DrawItem[]
  loading: boolean
  editorContent: string
  onInsert: (id: string, size: string, zoom: string) => void
  onRename: (id: string, title: string) => void
  onDelete: (id: string) => void
  onDeleteUnused: (ids: string[]) => void
  onNew: () => void
  onClose: () => void
}>) {
  const [confirmAction, setConfirmAction] = useState<{ message: string; onConfirm: () => void } | null>(null)

  const usedIds = new Set<string>()
  const re = /\[draw:([a-zA-Z0-9_-]+)/g
  let m
  while ((m = re.exec(editorContent)) !== null) usedIds.add(m[1])
  const unusedDrawings = drawings.filter(d => !usedIds.has(d.id))

  const handleDelete = (id: string) => {
    const title = drawings.find(d => d.id === id)?.title || 'Untitled'
    setConfirmAction({
      message: `Delete "${title}"?`,
      onConfirm: () => { onDelete(id); setConfirmAction(null) },
    })
  }

  const handleDeleteUnused = () => {
    const count = unusedDrawings.length
    setConfirmAction({
      message: `Delete ${count} unused drawing${count > 1 ? 's' : ''}? This cannot be undone.`,
      onConfirm: () => { onDeleteUnused(unusedDrawings.map(d => d.id)); setConfirmAction(null) },
    })
  }

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center">
      <button
        type="button"
        className="absolute inset-0 bg-black/60 backdrop-blur-sm border-0"
        onClick={onClose}
        aria-label="Close dialog"
      />
      <dialog
        open
        className="relative z-[1] w-full max-w-2xl mx-4 m-0 p-0 bg-dark-bg-secondary rounded-xl border border-dark-border-subtle shadow-2xl overflow-hidden flex flex-col max-h-[80vh]"
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-dark-border-subtle">
          <h3 className="text-lg font-semibold text-dark-text-primary">Drawings</h3>
          <div className="flex items-center gap-2">
            <button
              onClick={onNew}
              className="px-3 py-1.5 rounded-lg text-xs font-semibold bg-primary-600 text-white hover:bg-primary-500 transition-colors"
            >
              + New Drawing
            </button>
            <button
              onClick={onClose}
              className="text-dark-text-tertiary hover:text-dark-text-primary transition-colors"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>

        {/* Body */}
        <div className="overflow-y-auto p-6">
          {loading && (
            <p className="text-center text-sm text-dark-text-tertiary py-8">Loading drawings...</p>
          )}
          {!loading && drawings.length === 0 && (
            <p className="text-center text-sm text-dark-text-tertiary py-8">No drawings yet. Create one above!</p>
          )}
          {!loading && drawings.length > 0 && (
            <>
              {unusedDrawings.length > 0 && (
                <div className="flex items-center justify-between gap-2 mb-3 px-3 py-2.5 rounded-lg bg-red-500/10 border border-red-500/20">
                  <span className="text-xs text-red-300">{unusedDrawings.length} unused drawing{unusedDrawings.length > 1 ? 's' : ''}</span>
                  <button
                    onClick={handleDeleteUnused}
                    className="px-2.5 py-1 rounded text-xs font-medium bg-red-500/15 text-red-400 hover:bg-red-500/25 transition-colors"
                  >
                    Delete all unused
                  </button>
                </div>
              )}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                {drawings.map(d => (
                  <DrawCard
                    key={d.id}
                    drawing={d}
                    isUsed={usedIds.has(d.id)}
                    onInsert={onInsert}
                    onRename={onRename}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </>
          )}
        </div>

        {/* Confirmation dialog overlay */}
        {confirmAction && (
          <div className="absolute inset-0 z-10 flex items-center justify-center">
            <button
              type="button"
              className="absolute inset-0 bg-black/45 backdrop-blur-sm rounded-xl border-0"
              onClick={() => setConfirmAction(null)}
              aria-label="Close confirmation"
            />
            <dialog
              open
              className="relative z-[1] m-0 p-6 bg-dark-bg-secondary rounded-xl border border-dark-border-subtle shadow-2xl max-w-[340px] text-center"
            >
              <p className="text-sm font-medium text-dark-text-primary mb-4">{confirmAction.message}</p>
              <div className="flex gap-2 justify-center">
                <button
                  onClick={() => setConfirmAction(null)}
                  className="px-3 py-1.5 rounded-lg text-xs font-medium border border-dark-border-subtle text-dark-text-secondary hover:bg-dark-bg-tertiary transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={confirmAction.onConfirm}
                  className="px-3 py-1.5 rounded-lg text-xs font-semibold bg-red-600 text-white hover:bg-red-500 transition-colors"
                >
                  Delete
                </button>
              </div>
            </dialog>
          </div>
        )}
      </dialog>
    </div>
  )
}

// ── EditDrawModal ────────────────────────────────────────────────

